const axios = require('axios');
const { JSDOM } = require('jsdom');

exports.fetchUrlMetadata = async (req, res) => {
  try {
    const url = req.query.url;
    if (!url) {
      res.status(400).send('URL parameter is required');
      return;
    }

    const response = await axios.get(url);
    const dom = new JSDOM(response.data);
    const document = dom.window.document;

    const getMetaTag = (name) => {
      return document.querySelector(`meta[property='${name}']`)?.getAttribute('content') ||
             document.querySelector(`meta[name='${name}']`)?.getAttribute('content');
    };

    const metadata = {
      title: document.querySelector('title')?.textContent,
      description: getMetaTag('description'),
      ogTitle: getMetaTag('og:title'),
      ogDescription: getMetaTag('og:description'),
      ogImage: getMetaTag('og:image'),
      ogUrl: getMetaTag('og:url')
    };

    res.status(200).json(metadata);
  } catch (error) {
    res.status(500).send('Error fetching URL metadata');
  }
};